arguments.new_str:
using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 breaking change #1: Discriminator renamed from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator" — preserve for backward compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 breaking change #2: Id format changed from "EntityType|Key" to just "Key".
            // Existing documents have ids like "Product|123" — preserve that format.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonPropertyName("id")
                  .HasValueGenerator<ProductIdGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 breaking change #3: Sync APIs (ToList, First, etc.) removed for Cosmos.
        // While we fix call sites to use async, this is noted in CosmosQuery.cs.
    }
}

// EF Core 9 breaking change #4: HasIndex() now throws for Cosmos (was a silent no-op in EF 8).
// Removed the HasIndex call above — Cosmos does not support secondary indexes via EF.

class Product { public int Id { get; set; } public string Sku { get; set; } }

// Preserves the EF Core 8 "Product|{key}" id format for existing documents.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;
class ProductIdGenerator : ValueGenerator<string>
{
    public override string Next(EntityEntry entry) => $"Product|{entry.Property("Id").CurrentValue}";
    public override bool GeneratesTemporaryValues => false;
}

