// Preserves the EF Core 8 "Product|{key}" id format for existing documents.
class ProductIdGenerator : ValueGenerator<string>
{
    public override string Next(EntityEntry entry) => $"Product|{entry.Property("Id").CurrentValue}";
    public override bool GeneratesTemporaryValues => false;
}

